type ProofType = 'lien' | 'capture' | 'code' | 'audit';
type ClientValidation = 'en_attente' | 'approuve' | 'conteste';

interface DeliverableProof {
  type: ProofType;
  label: string;
  url?: string;
  description: string;
  submittedAt: string;
}

interface MissionRecommendation {
  id: string;
  title: string;
  priority: 'critical' | 'high' | 'medium' | 'low';
  category: string;
  // Delivery proof
  proof?: DeliverableProof;
  clientValidation?: ClientValidation;
}

interface MissionOrder {
  id: string;
  clientName: string;
  clientEmail: string;
  clientCompany: string;
  clientPhone?: string;
  analyzedUrl: string;
  aeoScore: number;
  auditDate: string;
  recommendations: MissionRecommendation[];
  status: MissionStatus;
  budget: number;
  currency: string;
  deadline: string;
  createdAt: string;
  updatedAt: string;
  notes?: string;
  completedRecommendations?: string[];
  // Escrow & Validation
  escrowStatus?: EscrowStatus;
  postAuditScore?: number;
  postAuditDate?: string;
  isReauditing?: boolean;
}

interface MissionOrdersProps {
  onBack: () => void;
  user: User | null;
  onNavigate: (view: string) => void;
}

