  livraison: { label: 'En validation', color: 'text-purple-400', bg: 'bg-purple-500/10 border-purple-500/20', icon: FileCheck },
  termine: { label: 'Terminé', color: 'text-green-400', bg: 'bg-green-500/10 border-green-500/20', icon: CheckCircle2 },
  refuse: { label: 'Refusé', color: 'text-red-400', bg: 'bg-red-500/10 border-red-500/20', icon: XCircle },
};

const ESCROW_CONFIG: Record<EscrowStatus, { label: string; color: string; icon: React.ElementType; desc: string }> = {
  bloque: { label: 'Fonds bloqués', color: 'text-amber-400', icon: Lock, desc: 'Les fonds sont sécurisés en escrow. Ils seront libérés après validation du client.' },
  en_validation: { label: 'En validation client', color: 'text-purple-400', icon: ShieldCheck, desc: 'Le travail est soumis. En attente de validation par le client pour libérer les fonds.' },
  libere: { label: 'Fonds libérés', color: 'text-green-400', icon: Unlock, desc: 'Le client a validé le travail. Les fonds ont été versés à l\'agence.' },
  litige: { label: 'Litige en cours', color: 'text-red-400', icon: AlertCircle, desc: 'Le client conteste la livraison. Un médiateur CitedBy.ai intervient.' },
