              <div>
                <label className="block text-xs text-gray-500 uppercase tracking-wider mb-2">Type de preuve</label>
                <div className="flex gap-2">
                  {([
                    { key: 'lien' as const, label: 'Lien URL', icon: Link },
                    { key: 'code' as const, label: 'Code', icon: Code },
                    { key: 'capture' as const, label: 'Capture', icon: Image },
                    { key: 'audit' as const, label: 'Audit', icon: ScanLine },
                  ]).map(t => (
                    <button key={t.key} onClick={() => setProofForm(p => ({ ...p, type: t.key }))}
                      className={`flex-1 py-2 rounded-xl text-xs font-medium border flex items-center justify-center gap-1.5 transition-all ${proofForm.type === t.key ? 'bg-purple-500/20 border-purple-500/30 text-purple-300' : 'bg-white/[0.03] border-white/[0.06] text-gray-500 hover:bg-white/[0.06]'}`}>
                      <t.icon size={13} /> {t.label}
                    </button>
                  ))}
                </div>
              </div>
              {(proofForm.type === 'lien' || proofForm.type === 'capture') && (
                <div>
                  <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">URL du livrable</label>
                  <input type="url" value={proofForm.url} onChange={e => setProofForm(p => ({ ...p, url: e.target.value }))} placeholder="https://..."
                    className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50" />
                </div>
              )}
              <div>
                <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1.5">Description du travail réalisé *</label>
                <textarea value={proofForm.description} onChange={e => setProofForm(p => ({ ...p, description: e.target.value }))} placeholder="Décrivez ce qui a été fait, les modifications apportées, les fichiers livrés..."
                  rows={3} className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-2.5 text-sm text-white placeholder-gray-600 focus:outline-none focus:border-purple-500/50 resize-none" />
              </div>
            </div>
            <div className="p-5 border-t border-white/[0.06] flex justify-between">
              <button onClick={() => setProofModal(null)} className="px-4 py-2.5 text-sm text-gray-400 hover:text-white transition-colors">Annuler</button>
              <button onClick={handleSubmitProof} disabled={!proofForm.description.trim()}
                className="px-5 py-2.5 bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold rounded-xl text-sm disabled:opacity-40 disabled:cursor-not-allowed flex items-center gap-2 transition-all">
                <Upload size={14} /> Soumettre la preuve
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default MissionOrders;

